string pipeDelimitedVariable = GetVariableValue("vDocIDs");

        // Create XML document
        XmlDocument xmlDoc = new XmlDocument();
        XmlElement rootNode = xmlDoc.CreateElement("Documents");
        xmlDoc.AppendChild(rootNode);

        // Split the pipe delimited string into individual GUIDs
        string[] documents = pipeDelimitedVariable.Split('|');

        // Create a new XML node for each GUID
        foreach (string document in documents)
        {
            XmlElement documentNode = xmlDoc.CreateElement("DocumentID");
            documentNode.InnerText = document;
            rootNode.AppendChild(documentNode);
        }

        // Get the XML as a string
        string xmlOutput = xmlDoc.OuterXml;

return xmlOutput;

XmlNodeList RoutingOptionsList = _context.XmlVariables["dRoutingOptions"].GetXmlNodes("//Row");

System.Xml.XmlDocument xWFDataXml = new XmlDocument();
var xWFData = _context.XmlVariables["xWFData"].GetXmlNode("//*").OuterXml;
xWFDataXml.LoadXml(xWFData);
System.Xml.XmlElement root = xWFDataXml.DocumentElement;

System.Xml.XPath.XPathNavigator requestNavigator = xWFDataXml.CreateNavigator();
bool found = false;

foreach(XmlNode RoutingOptionsNode in RoutingOptionsList){

    string condition = RoutingOptionsNode.SelectSingleNode("Condition").InnerText;

    if (condition != "" && !found) {
      System.Xml.XPath.XPathExpression expression = System.Xml.XPath.XPathExpression.Compile(condition);
      if (expression.ReturnType.Equals(System.Xml.XPath.XPathResultType.Boolean)){
        if ((bool)requestNavigator.Evaluate(expression)){

            XmlNode NodeRoutingSelectionNote =  root.SelectSingleNode("//SYS_Selected_Route_RoutingSelectionNote");
            string RoutingSelectionNote = RoutingOptionsNode.SelectSingleNode("RoutingSelectionNote").InnerText;
            NodeRoutingSelectionNote.InnerText = RoutingSelectionNote;

            XmlNode NodeCondition =  root.SelectSingleNode("//SYS_Selected_Route_Condition");
            NodeCondition.InnerText = condition;

            XmlNode NodeSelectedRouteOptions = root.SelectSingleNode("//SYS_Selected_Route_Options");
            string RouteOptions = RoutingOptionsNode.SelectSingleNode("RouteOptions").InnerText;
            if (RouteOptions != "NA") {
                NodeSelectedRouteOptions.InnerText = RouteOptions;
            } else {
                NodeSelectedRouteOptions.InnerText = "";
            }

            XmlNode NodeSelectedRouteDisplayName = root.SelectSingleNode("//SYS_Selected_Route_DisplayName");
            string DisplayName = RoutingOptionsNode.SelectSingleNode("DisplayName").InnerText;
            NodeSelectedRouteDisplayName.InnerText = DisplayName;

            XmlNode NodeSelectedRouteStageName =  root.SelectSingleNode("//SYS_Selected_Route_StageName");
            string StageName = RoutingOptionsNode.SelectSingleNode("StageName").InnerText;
            if (StageName != "No Change") {
                NodeSelectedRouteStageName.InnerText = StageName;
            }

            XmlNode NodeSelectedRouteTaskUser =  root.SelectSingleNode("//SYS_Selected_Route_TaskUser");
            string TaskUser = RoutingOptionsNode.SelectSingleNode("TaskUser").InnerText;
            if (TaskUser != "No Change") {
                NodeSelectedRouteTaskUser.InnerText = GetVariableValue(TaskUser);
            }

            XmlNode NodeSelectedRouteTaskGroup =  root.SelectSingleNode("//SYS_Selected_Route_TaskGroup");
            string TaskGroup = RoutingOptionsNode.SelectSingleNode("TaskGroup").InnerText;
            if (TaskGroup != "NA") {
                NodeSelectedRouteTaskGroup.InnerText = TaskGroup;
            }

            XmlNode NodeSelectedRouteStepType =  root.SelectSingleNode("//SYS_Selected_Route_StepType");
            string StepType = RoutingOptionsNode.SelectSingleNode("StepType").InnerText;
            NodeSelectedRouteStepType.InnerText = StepType;

            XmlNode NodeSelectedRouteLinktoNextTask =  root.SelectSingleNode("//SYS_Selected_Route_LinktoNextTask");
            string LinkToNextTask = RoutingOptionsNode.SelectSingleNode("LinkToNextTask").InnerText;
            NodeSelectedRouteLinktoNextTask.InnerText = LinkToNextTask;

            XmlNode NodeSelectedRouteEmailBody =  root.SelectSingleNode("//SYS_Selected_Route_EmailBody");
            string EmailBody = RoutingOptionsNode.SelectSingleNode("EmailBody").InnerText;
            NodeSelectedRouteEmailBody.InnerText = EmailBody;

            XmlNode NodeSelectedRouteInstructions =  root.SelectSingleNode("//SYS_Selected_Route_Instructions");
            string Instructions = RoutingOptionsNode.SelectSingleNode("Instructions").InnerText;
            NodeSelectedRouteInstructions.InnerText = Instructions;

            XmlNode NodeSelectedRouteNotes =  root.SelectSingleNode("//SYS_Selected_Route_Notes");
            string Notes = RoutingOptionsNode.SelectSingleNode("Notes").InnerText;
            NodeSelectedRouteNotes.InnerText = Notes;

            found = true;
        }
      }
    }
}

return xWFDataXml.OuterXml;

